    "# Paso 3: Verificar qué LLMs están configurados\n",
    "google_key      = os.environ.get(\"GOOGLE_API_KEY\")\n",
    "# openai_key      = os.environ.get(\"OPENAI_API_KEY\")\n",
    "openrouter_key  = os.environ.get(\"OPENROUTER_API_KEY\")\n",
