    "#   5. Skill registrada en registry.py con SKILL_METADATA completo\n",
    "#   6. Hiperparámetros justificados: temperature=0.0, top_p=0.1, freq_penalty=0.3, max_tokens=800\n",
    "# ============================================================\n",
    "import os\n",
