    "\n",
    "load_dotenv(override=True)\n",
    "\n",
    "# ─────────────────────────────────────────────────────────────────────────────\n",
    "# PASO 1 — Definir 3 tools específicas del dominio: Ciberseguridad\n",
    "# ─────────────────────────────────────────────────────────────────────────────\n",
    "\n",
    "@tool\n",
    "def consultar_cve(cve_id: str) -> str:\n",
    "    \"\"\"Consulta la base de datos NVD simulada para obtener descripción y CVSS de un CVE.\n",
    "    Usala cuando el usuario mencione un identificador CVE (ej: CVE-2021-44228).\n",
    "    Args: cve_id (str): Identificador en formato CVE-YYYY-NNNNN.\n",
    "    Returns: Descripción técnica, puntaje CVSS v3.1 y vector de ataque.\"\"\"\n",
    "    # OWASP: Sanitización — evitar path traversal y prompt injection\n",
    "    safe_id = cve_id.strip().upper().replace(\"/\", \"\").replace(\"..\", \"\")\n",
    "    nvd = {\n",
    "        \"CVE-2021-44228\": (\n",
    "            \"Log4Shell — RCE en Apache Log4j 2 via JNDI lookup. \"\n",
    "            \"CVSS v3.1: 10.0 (CRITICO). Afecta Log4j 2.0-beta9 a 2.14.1. \"\n",
    "            \"Vector: AV:N/AC:L/PR:N/UI:N/S:C/C:H/I:H/A:H. Parche: 2.17.1+.\"\n",
    "        ),\n",
    "        \"CVE-2023-0669\": (\n",
    "            \"GoAnywhere MFT — Deserializacion insegura pre-auth que permite RCE. \"\n",
    "            \"CVSS v3.1: 9.8 (CRITICO). Explotada activamente por ransomware Cl0p. \"\n",
    "            \"Vector: AV:N/AC:L/PR:N/UI:N/S:U/C:H/I:H/A:H. Parche: 7.1.2+.\"\n",
    "        ),\n",
    "        \"CVE-2024-3400\": (\n",
    "            \"PAN-OS GlobalProtect — Inyeccion de comandos OS en gateway VPN Palo Alto. \"\n",
    "            \"CVSS v3.1: 10.0 (CRITICO). Explotada como zero-day (Operacion MidnightEclipse). \"\n",
    "            \"Vector: AV:N/AC:L/PR:N/UI:N/S:C/C:H/I:H/A:H. Parche: inmediato requerido.\"\n",
    "        ),\n",
    "        \"CVE-2022-30190\": (\n",
    "            \"Follina (MSDT) — Ejecucion de codigo via archivos Office sin macros. \"\n",
    "            \"CVSS v3.1: 7.8 (ALTO). Explota el protocolo ms-msdt://. \"\n",
    "            \"Vector: AV:L/AC:L/PR:N/UI:R/S:U/C:H/I:H/A:H. Parche: MS KB5014699.\"\n",
    "        ),\n",
    "    }\n",
    "    r = nvd.get(safe_id)\n",
    "    if r:\n",
    "        return f\"[NVD] {safe_id}: {r}\"\n",
    "    return (\n",
    "        f\"CVE '{safe_id}' no encontrado en la DB local. \"\n",
    "        \"Consulta https://nvd.nist.gov para datos actualizados.\"\n",
    "    )\n",
    "\n",
    "\n",
    "@tool\n",
    "def calcular_cvss_severidad(puntuacion: float) -> str:\n",
    "    \"\"\"Clasifica un puntaje CVSS v3.x en nivel de severidad oficial NIST/FIRST\n",
    "    y genera el SLA de respuesta recomendado.\n",
    "    Usala cuando tengas un numero CVSS (0.0-10.0) y necesites priorizar la respuesta.\n",
    "    Args: puntuacion (float): Puntaje CVSS entre 0.0 y 10.0.\n",
    "    Returns: Nivel de severidad, SLA y accion recomendada.\"\"\"\n",
    "    score = float(puntuacion)\n",
    "    if not (0.0 <= score <= 10.0):\n",
    "        return \"Error: el puntaje CVSS debe estar entre 0.0 y 10.0.\"\n",
    "    if score == 0.0:\n",
    "        nivel, sla, accion = \"NINGUNO\", \"N/A\", \"Sin impacto conocido. Monitoreo pasivo.\"\n",
    "    elif score <= 3.9:\n",
    "        nivel, sla, accion = \"BAJO\", \"90 dias\", \"Incluir en el proximo ciclo de parchado.\"\n",
    "    elif score <= 6.9:\n",
    "        nivel, sla, accion = \"MEDIO\", \"30 dias\", \"Parchado planificado con prioridad moderada.\"\n",
    "    elif score <= 8.9:\n",
    "        nivel, sla, accion = \"ALTO\", \"7 dias\", \"Parchado urgente. Verificar exposicion perimetral.\"\n",
    "    else:\n",
    "        nivel, sla, accion = (\n",
    "            \"CRITICO\", \"24-48 horas\",\n",
    "            \"Respuesta INMEDIATA: aislar sistemas afectados, aplicar mitigacion temporal, \"\n",
    "            \"notificar al CERT y activar el Plan de Respuesta a Incidentes.\"\n",
    "        )\n",
    "    return (\n",
    "        f\"CVSS {score:.1f} | Severidad: {nivel} | SLA: {sla}\\n\"\n",
    "        f\"Accion: {accion}\"\n",
    "    )\n",
    "\n",
    "\n",
    "@tool\n",
    "def clasificar_ioc(indicador: str) -> str:\n",
    "    \"\"\"Clasifica un Indicador de Compromiso (IoC) y lo valida contra la base de\n",
    "    inteligencia de amenazas (hashes malware, IPs C2, dominios phishing).\n",
    "    Usala cuando el usuario proporcione un hash MD5/SHA256, IP sospechosa o dominio.\n",
    "    Args: indicador (str): Hash, IP, dominio o URL a analizar.\n",
