    "        \"e3b0c44298fc1c149afbf4c8996fb924\": \"HASH SHA256 | LIMPIO — Archivo vacio (0 bytes).\",\n",
    "        \"185.220.101.1\": (\n",
    "            \"IP | MALICIOSO — Nodo Tor usado como C2 por campanas ransomware. \"\n",
    "            \"Bloquear en firewall. Fuente: Emerging Threats.\"\n",
    "        ),\n",
    "        \"45.142.212.100\": (\n",
    "            \"IP | MALICIOSO — C2 del grupo Lazarus (APT38-DPRK). \"\n",
    "            \"Asociado a robo de credenciales bancarias. Aislar y reportar al CERT.\"\n",
    "        ),\n",
    "        \"evil-update.com\": (\n",
    "            \"DOMINIO | MALICIOSO — Phishing que suplanta Windows Update. \"\n",
    "            \"Distribuye infostealer Raccoon v2.\"\n",
