    "            \"DOMINIO | MALICIOSO — Servidor JNDI para exfiltracion via Log4Shell (CVE-2021-44228).\"\n",
    "        ),\n",
    "    }\n",
    "    r = ioc_db.get(safe_ioc)\n",
    "    if r:\n",
    "        return f\"[Threat Intel] '{indicador}': {r}\"\n",
    "    # Heuristica de tipo si no esta en la DB\n",
    "    if len(safe_ioc) in (32, 40, 64, 128):\n",
    "        tipo = \"HASH\"\n",
    "    elif safe_ioc.replace(\".\", \"\").isdigit() or \":\" in safe_ioc:\n",
