    "    return (\n",
    "        f\"[Threat Intel] '{indicador}' | Tipo: {tipo} | Veredicto: DESCONOCIDO. \"\n",
    "        \"No en la DB local. Verificar en VirusTotal, AlienVault OTX o MISP.\"\n",
    "    )\n",
    "\n",
